            <tr>
             <td style="text-align: center;">
             </td>
             <td align="left" class="content" style="text-align: center;" width="908">
              <a class="image-link" href="https://substack.com/redirect/8c6f1d1e-e046-4332-9be5-040b8a9d10c0?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="wide-image" data-attrs='{"src":"https://substack-post-media.s3.amazonaws.com/public/images/e9264294-b0d9-46b9-922e-0c944ed6a649_908x515.png","srcNoWatermark":null,"fullscreen":null,"imageSize":null,"height":515,"width":908,"resizeWidth":null,"bytes":null,"alt":null,"title":null,"type":null,"href":null,"belowTheFold":true,"topImage":false,"internalRedirect":null}' height="311.94933920704847" src="https://substackcdn.com/image/fetch/w_1816,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fe9264294-b0d9-46b9-922e-0c944ed6a649_908x515.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="550"/>
              </a>
