             <td style="text-align: center;">
             </td>
             <td align="left" class="content" style="text-align: center;" width="908">
              <a class="image-link" href="https://substack.com/redirect/3355684a-5f44-4011-8568-7224bd9fe2af?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="wide-image" data-attrs='{"src":"https://substack-post-media.s3.amazonaws.com/public/images/cc05f351-6ab4-4185-8af0-89ab5629b6a2_908x326.png","srcNoWatermark":null,"fullscreen":null,"imageSize":null,"height":326,"width":908,"resizeWidth":null,"bytes":null,"alt":null,"title":null,"type":null,"href":null,"belowTheFold":true,"topImage":false,"internalRedirect":null}' height="197.46696035242292" src="https://substackcdn.com/image/fetch/w_1816,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fcc05f351-6ab4-4185-8af0-89ab5629b6a2_908x326.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="550"/>
              </a>
             </td>
