           <em>
            <a href="https://substack.com/redirect/2d085523-a884-4474-8ce5-39909af3d203?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="text-decoration: underline;">
