             <td style="text-align: center;">
             </td>
             <td align="left" class="content" style="text-align: center;" width="551">
              <a class="image-link" href="https://substack.com/redirect/c934846c-c5b0-4dc3-89bb-75fd43897d49?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
